// Pac-Man Ghost (Blinky) — standalone figurine
// Revolve-based body with per-label coloring, clean eye geometry
const { Manifold, CrossSection } = api;

// ─── Design constants ───────────────────────────────────────────────────────
const GH_R    = 8.5;
const BODY_H  = 30.0;
const HEM_Z   = 6.5;    // raise the hem so teeth are part of the skirt, not the floor
const NUM_TEETH = 4;

// ─── Body profile (revolved) ────────────────────────────────────────────────
const pts = [];

pts.push([0, 0]);
// Base gradually flares out
pts.push([GH_R * 0.42, 1.0]);
pts.push([GH_R * 0.66, HEM_Z * 0.5]);
pts.push([GH_R * 0.78, HEM_Z]);

// Waist: gentle pinch above hem
pts.push([GH_R * 0.74, HEM_Z + 1.8]);
pts.push([GH_R * 0.77, HEM_Z + 3.8]);

// Mid body widens
pts.push([GH_R * 0.84, HEM_Z + 6.5]);
pts.push([GH_R * 0.94, HEM_Z + 9.5]);

// Shoulder — widest zone
pts.push([GH_R * 1.00, HEM_Z + 12.5]);
pts.push([GH_R * 1.00, HEM_Z + 15.5]);

// Dome arc: true quarter-circle
const shoulderTopZ = HEM_Z + 15.5;
const crownZ = BODY_H;
const arcSteps = 24;
for (let i = 1; i <= arcSteps; i++) {
  const t = (i / arcSteps) * (Math.PI / 2);
  pts.push([Math.cos(t) * GH_R, shoulderTopZ + Math.sin(t) * (crownZ - shoulderTopZ)]);
}
pts.push([0, crownZ]);

const section = CrossSection.ofPolygons([pts]);
let ghostBody = section.revolve(72);

// ─── Teeth: 4 scallops at 45° offsets ────────────────────────────────────────
// 45-135-225-315 deg: from front, two teeth visible symmetrically on each side
const TOOTH_R  = 2.8;
const TOOTH_RZ = 2.2;
const toothRingR   = GH_R * 0.63;
// Raise teeth to the hem level so they integrate as a skirt, not separate feet
const toothCenterZ = HEM_Z + 0.5;

let teethMesh = null;
for (let i = 0; i < NUM_TEETH; i++) {
  const angle = (i / NUM_TEETH) * Math.PI * 2 + Math.PI / 4;
  const tx = Math.cos(angle) * toothRingR;
  const ty = Math.sin(angle) * toothRingR;
  const tooth = Manifold.sphere(1, 30)
    .scale([TOOTH_R, TOOTH_R, TOOTH_RZ])
    .translate([tx, ty, toothCenterZ]);
  teethMesh = teethMesh ? teethMesh.add(tooth) : tooth;
}
ghostBody = ghostBody.add(teethMesh);

// Flat base
ghostBody = ghostBody.subtract(
  Manifold.cube([GH_R * 6, GH_R * 6, 14], true).translate([0, 0, -7])
);

// ─── Eye geometry ────────────────────────────────────────────────────────────
// Big expressive eyes — classic ghost appearance
const EYE_Z   = 22.5;    // upper body, close to shoulder
const EYE_SEP = 3.2;     // separation
const EYE_RX  = 2.9;     // wide
const EYE_RY  = 1.9;     // depth
const EYE_RZ  = 3.7;     // tall

const bodyREye   = GH_R * 1.0;
const bodyFrontY = -Math.sqrt(Math.max(0.1, bodyREye * bodyREye - EYE_SEP * EYE_SEP));
const eyeCY = bodyFrontY - EYE_RY * 0.65;

function makeEyeWhite(cx) {
  return Manifold.sphere(1, 56)
    .scale([EYE_RX, EYE_RY, EYE_RZ])
    .translate([cx, eyeCY, EYE_Z]);
}
const leftWhite  = makeEyeWhite(-EYE_SEP);
const rightWhite = makeEyeWhite(EYE_SEP);

// Pupils
const PUP_R  = 1.15;
const PUP_DX = -0.5;
const PUP_DZ = -0.75;
const pupilY  = eyeCY - EYE_RY + PUP_R * 0.45;

function makePupil(cx) {
  return Manifold.sphere(PUP_R, 26)
    .translate([cx + PUP_DX, pupilY, EYE_Z + PUP_DZ]);
}
const leftPupil  = makePupil(-EYE_SEP);
const rightPupil = makePupil(EYE_SEP);

// ─── Label and combine ────────────────────────────────────────────────────────
const bodyLabeled       = api.label(ghostBody,  'body',   { color: '#ef0000' });
const leftWhiteLabeled  = api.label(leftWhite,  'eyeL',   { color: '#ffffff' });
const rightWhiteLabeled = api.label(rightWhite, 'eyeR',   { color: '#ffffff' });
const leftPupilLabeled  = api.label(leftPupil,  'pupilL', { color: '#2244ee' });
const rightPupilLabeled = api.label(rightPupil, 'pupilR', { color: '#2244ee' });

return bodyLabeled
  .add(leftWhiteLabeled)
  .add(rightWhiteLabeled)
  .add(leftPupilLabeled)
  .add(rightPupilLabeled);
